    public Dictionary<string, string> ParseConfigurationWithXmlDocument(string xmlContent)
    {
        var settings = new Dictionary<string, string>();
        var xmlDoc = new XmlDocument();
        
        var readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            XmlResolver = new XmlUrlResolver(),
            ValidationType = ValidationType.DTD
        };

        using (var stringReader = new StringReader(xmlContent))
        using (var xmlReader = XmlReader.Create(stringReader, readerSettings))
        {
            xmlDoc.Load(xmlReader);
        }

        XmlNodeList settingNodes = xmlDoc.SelectNodes("//setting");
        if (settingNodes != null)
        {
            foreach (XmlNode node in settingNodes)
            {
                string key = node.Attributes?["key"]?.Value;
                string value = node.Attributes?["value"]?.Value ?? node.InnerText;
                
                if (!string.IsNullOrEmpty(key))
                {
                    settings[key] = value;
                }
            }
        }

        XmlNodeList configNodes = xmlDoc.SelectNodes("//configuration/*");
        if (configNodes != null)
        {
            foreach (XmlNode node in configNodes)
            {
                if (node.NodeType == XmlNodeType.Element && node.Name != "setting")
                {
                    string key = node.Name;
                    string value = node.InnerText;
                    settings[key] = value;
                }
            }
        }

        return settings;
    }

